}

// Set up a logger to track sequence
window.sequenceLog = window.sequenceLog || [];
const observer = new MutationObserver((mutations) => {
  mutations.forEach(mutation => {
    if (mutation.type === 'attributes' && mutation.attributeName === 'class') {
      const target = mutation.target;
      const rect = target.getBoundingClientRect();
      window.sequenceLog.push({
        time: Date.now(),
        classes: target.className,
        position: {x: Math.round(rect.left), y: Math.round(rect.top)}
      });
    }
  });
});

// Find all squares and observe them
const squares = document.querySelectorAll('div[class*="css-"]');
squares.forEach(sq => {
  observer.observe(sq, { attributes: true });
});

return {setup: 'complete', watching: squares.length};

